(function () {
  function addStyle() { if (document.getElementById('bdv-style')) return; var s = document.createElement('style'); s.id = 'bdv-style'; s.textContent = '.bdv-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.bdv-board{position:relative;height:260px;border:1px solid #e5e7eb;border-radius:12px;background:#f8fafc;margin:12px 0}.bdv-line{position:absolute;height:3px;background:#cbd5e1;transform-origin:left center}.bdv-node{position:absolute;width:44px;height:44px;border-radius:999px;border:2px solid #94a3b8;background:#fff;display:flex;align-items:center;justify-content:center;font-weight:700;transform:translate(-50%,-50%);transition:.25s}.bdv-node.seen{background:#fff3cd;border-color:#ffc107}.bdv-node.done{background:#d4edda;border-color:#28a745}.bdv-actions{display:flex;gap:8px;flex-wrap:wrap}.bdv-state{padding:10px;border-radius:8px;background:#e8f4fd;border-left:4px solid #007bff}.bdv-order{margin-top:8px;color:#334155}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.bdvMounted) return; host.dataset.bdvMounted = '1'; addStyle(); var pts = {1:[50,12],2:[22,36],3:[78,36],4:[18,76],5:[50,78],6:[82,76]}, adj = {1:[2,3],2:[1,4,5],3:[1,5,6],4:[2],5:[2,3],6:[3]}; host.innerHTML = '<div class="bdv-wrap"><h4>🔎 BFS/DFS trên đồ thị</h4><div class="bdv-actions"><button type="button" data-bfs>BFS từ đỉnh 1</button><button type="button" data-dfs>DFS từ đỉnh 1</button><button type="button" data-reset>Reset</button></div><div class="bdv-board"></div><div class="bdv-state">Sẵn sàng.</div><div class="bdv-order"></div></div>'; var board = host.querySelector('.bdv-board'), state = host.querySelector('.bdv-state'), orderEl = host.querySelector('.bdv-order'), timer = 0; function line(a, b) { var p = pts[a], q = pts[b], dx = q[0] - p[0], dy = q[1] - p[1], len = Math.sqrt(dx * dx + dy * dy), d = document.createElement('div'); d.className = 'bdv-line'; d.style.left = p[0] + '%'; d.style.top = p[1] + '%'; d.style.width = len + '%'; d.style.transform = 'rotate(' + Math.atan2(dy, dx) + 'rad)'; board.appendChild(d); } function draw() { board.innerHTML = ''; [[1,2],[1,3],[2,4],[2,5],[3,5],[3,6]].forEach(function (e) { line(e[0], e[1]); }); Object.keys(pts).forEach(function (k) { var n = document.createElement('div'); n.className = 'bdv-node'; n.dataset.v = k; n.style.left = pts[k][0] + '%'; n.style.top = pts[k][1] + '%'; n.textContent = k; board.appendChild(n); }); } function reset() { clearInterval(timer); draw(); state.textContent = 'Sẵn sàng.'; orderEl.textContent = ''; } function seq(mode) { var seen = {1:true}, out = [], work = [1]; while (work.length) { var v = mode === 'bfs' ? work.shift() : work.pop(); out.push(v); adj[v].slice().reverse().forEach(function (u) { if (!seen[u]) { seen[u] = true; if (mode === 'bfs') work.push(u); else work.push(u); } }); } return out; } function run(mode) { reset(); var order = seq(mode), i = 0, bag = [1]; timer = setInterval(function () { if (i >= order.length) { clearInterval(timer); state.textContent = 'Hoàn tất. Thứ tự: ' + order.join(' → '); return; } var v = order[i], node = host.querySelector('[data-v="' + v + '"]'); node.classList.add('seen'); state.textContent = (mode === 'bfs' ? 'Hàng đợi' : 'Ngăn xếp') + ' đang xử lý đỉnh ' + v + '. Trạng thái: ' + bag.join(', '); setTimeout(function () { node.classList.add('done'); }, 280); bag = order.slice(i + 1, i + 4); orderEl.textContent = 'Đã thăm: ' + order.slice(0, i + 1).join(' → '); i++; }, 650); } host.querySelector('[data-bfs]').addEventListener('click', function () { run('bfs'); }); host.querySelector('[data-dfs]').addEventListener('click', function () { run('dfs'); }); host.querySelector('[data-reset]').addEventListener('click', reset); reset(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="bfs-dfs-visualizer"]').forEach(mount); });
}());
